```python
class InvalidStudentIDError(Exception):
    def __init__(self, student_id):
        self.student_id = student_id
        super().__init__(f"Invalid student ID: {student_id}")

def validate_student_id(sid):
    if not isinstance(sid, str) or len(sid) != 6 or not sid.isdigit():
        raise InvalidStudentIDError(sid)
    return sid

try:
    validate_student_id("ABC123")
except InvalidStudentIDError as e:
    print(f"Error: {e}, ID was: {e.student_id}")
```

